func TestApplyEventCreationDefaultsAddsLocalPreferences(t *testing.T) {
	body := map[string]any{
		"summary":  "Doctor appointment",
		"location": "Charite Berlin, Chariteplatz 1, 10117 Berlin",
	}

	ApplyEventCreationDefaults(body)

	if got := body["summary"].(string); !strings.HasPrefix(got, "🏥 ") {
		t.Fatalf("summary = %q, want health emoji prefix", got)
	}
	if got := body["colorId"]; got != defaultEventColorID {
		t.Fatalf("colorId = %v, want %q", got, defaultEventColorID)
	}
	if got := body["description"].(string); !strings.Contains(got, "Chariteplatz 1") {
		t.Fatalf("description = %q, want location address included", got)
	}

	reminders := body["reminders"].(map[string]any)
	if got := reminders["useDefault"]; got != false {
		t.Fatalf("useDefault = %v, want false", got)
	}
	overrides := reminders["overrides"].([]any)
	if !hasPhoneReminder(overrides) {
		t.Fatalf("reminders = %#v, want one-day popup reminder", overrides)
	}
}

func TestApplyEventCreationDefaultsPreservesExplicitTextAndEnforcesEventPolicy(t *testing.T) {
	body := map[string]any{
		"summary":     "☕ Coffee with Alex",
		"description": "Catch up.",
		"colorId":     "5",
		"reminders": map[string]any{
			"overrides": []any{
				map[string]any{"method": "email", "minutes": 60},
			},
		},
	}

	ApplyEventCreationDefaults(body)

	if got := body["summary"]; got != "☕ Coffee with Alex" {
		t.Fatalf("summary = %q, want explicit emoji summary preserved", got)
	}
	if got := body["colorId"]; got != defaultEventColorID {
		t.Fatalf("colorId = %v, want sage color", got)
	}
	if got := body["description"]; got != "Catch up." {
		t.Fatalf("description = %q, want explicit description preserved", got)
	}
	if !hasPhoneReminder(body["reminders"].(map[string]any)["overrides"].([]any)) {
		t.Fatalf("reminders = %#v, want default one-day popup added", body["reminders"])
	}
}
